import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axiosInstance from '../api/axiosConfig';

const MyEnrolments = () => {
  const [enrolments, setEnrolments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState({});
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    fetchEnrolments();
  }, []);

  const fetchEnrolments = async () => {
    setLoading(true);
    setError('');
    try {
      const response = await axiosInstance.get('/api/enrolments/my');
      setEnrolments(response.data);
    } catch (err) {
      console.error(err);
      setError('Failed to fetch your enrolments. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleDrop = async (courseId, courseTitle) => {
    if (!window.confirm(`Are you sure you want to drop "${courseTitle}"?`)) {
      return;
    }

    setError('');
    setSuccess('');
    setActionLoading((prev) => ({ ...prev, [courseId]: true }));

    try {
      await axiosInstance.delete(`/api/enrolments/drop/${courseId}`);
      setSuccess(`Successfully dropped "${courseTitle}"`);
      // Update local state
      setEnrolments((prev) => prev.filter((item) => item.courseId !== courseId));
    } catch (err) {
      console.error(err);
      if (err.response && err.response.data && err.response.data.message) {
        setError(err.response.data.message);
      } else {
        setError('Failed to drop the course. Please try again.');
      }
    } finally {
      setActionLoading((prev) => ({ ...prev, [courseId]: false }));
      // Clear success alert
      setTimeout(() => setSuccess(''), 4000);
    }
  };

  const formatDate = (dateStr) => {
    if (!dateStr) return 'N/A';
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  return (
    <div className="container py-5 text-light">
      <div className="mb-5">
        <h2 className="fw-bold bg-gradient-primary-to-secondary text-transparent bg-clip-text d-inline-block">
          My Enrolments
        </h2>
        <p className="text-muted mb-0">Track and manage your registered courses</p>
      </div>

      {success && (
        <div className="alert alert-success border-0 bg-success bg-opacity-10 text-success rounded-3 mb-4 shadow-sm" role="alert">
          {success}
        </div>
      )}

      {error && (
        <div className="alert alert-danger border-0 bg-danger bg-opacity-10 text-danger rounded-3 mb-4 shadow-sm" role="alert">
          {error}
        </div>
      )}

      {loading ? (
        <div className="d-flex flex-column align-items-center justify-content-center py-5">
          <div className="spinner-border text-primary mb-3" role="status">
            <span className="visually-hidden">Loading...</span>
          </div>
          <span className="text-muted">Loading your enrolments...</span>
        </div>
      ) : enrolments.length === 0 ? (
        <div className="card bg-slate-800 border-0 text-center p-5 rounded-4 shadow-sm">
          <div className="card-body">
            <span className="fs-1 d-block mb-3">🎓</span>
            <h4 className="fw-bold">No active enrolments</h4>
            <p className="text-muted mb-4">You have not enrolled in any courses yet.</p>
            <Link to="/dashboard" className="btn btn-primary px-4 py-2 rounded-3 fw-semibold">
              Browse Available Courses
            </Link>
          </div>
        </div>
      ) : (
        <div className="row g-4">
          <div className="col-12 mb-2">
            <div className="bg-slate-800 rounded-3 p-3 border-start border-primary border-4 shadow-sm">
              <span className="fw-medium text-white">Active Courses:</span>{' '}
              <span className="badge bg-primary rounded-pill fs-6 px-3">{enrolments.length}</span>
            </div>
          </div>

          <div className="col-12">
            <div className="card border-0 bg-slate-800 shadow-sm rounded-4 overflow-hidden">
              <div className="table-responsive">
                <table className="table table-dark table-hover align-middle mb-0">
                  <thead className="bg-slate-900 text-muted small text-uppercase">
                    <tr>
                      <th className="py-3 px-4" style={{ width: '40%' }}>Course Details</th>
                      <th className="py-3 px-4">Instructor</th>
                      <th className="py-3 px-4">Enrolment Date</th>
                      <th className="py-3 px-4 text-end">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {enrolments.map((enrolment) => (
                      <tr key={enrolment.id}>
                        <td className="py-4 px-4">
                          <div className="d-flex flex-column">
                            <span className="fw-bold text-white fs-6">{enrolment.courseTitle}</span>
                            <span className="text-muted small mt-1">Course ID: {enrolment.courseId}</span>
                          </div>
                        </td>
                        <td className="py-4 px-4">
                          <span className="text-light">{enrolment.courseInstructor}</span>
                        </td>
                        <td className="py-4 px-4">
                          <span className="text-muted small">{formatDate(enrolment.enrolledAt)}</span>
                        </td>
                        <td className="py-4 px-4 text-end">
                          <button
                            className="btn btn-outline-danger btn-sm px-3 py-2 rounded-3 fw-medium d-inline-flex align-items-center gap-1"
                            onClick={() => handleDrop(enrolment.courseId, enrolment.courseTitle)}
                            disabled={actionLoading[enrolment.courseId]}
                          >
                            {actionLoading[enrolment.courseId] ? (
                              <>
                                <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                                Dropping...
                              </>
                            ) : (
                              <>
                                <span>Drop Course</span>
                              </>
                            )}
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default MyEnrolments;
